////////////////////////////////////////////////////////////////////////////////////
// Optimization 4 - Per-material kernel with offset/count
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_4(Inputs in, SimulationData GSD, int m, int n_lookups_mat, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups_mat ) return;

	int idx = offset + i;

	double p_energy = GSD.p_energy_samples[idx];

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			m,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[idx] = (unsigned long)(max_idx+1);
}

unsigned long long run_event_based_simulation_optimization_4(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	
		printf("Beginning event based simulation (optimization 4)...\n");

	int n_lookups = in.lookups;
	int threads = 256;
	int blocks = (n_lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaDeviceSynchronize());

	// Sort by material, then by energy within each material
	thrust::device_ptr<int> mat_ptr(GSD.mat_samples);
	thrust::device_ptr<double> energy_ptr(GSD.p_energy_samples);
	thrust::sort_by_key(mat_ptr, mat_ptr + n_lookups, energy_ptr);

	// Copy mat_samples to host to count per-material
	int * h_mat_samples = (int *) malloc(n_lookups * sizeof(int));
	cudaMemcpy(h_mat_samples, GSD.mat_samples, n_lookups * sizeof(int), cudaMemcpyDeviceToHost);

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < n_lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Sort each material's energies
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 0 )
		{
			thrust::device_ptr<double> e_ptr(GSD.p_energy_samples + offsets[m]);
			thrust::sort(e_ptr, e_ptr + num_samples_per_mat[m]);
		}
	}

	// Launch per-material kernels with offset
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 0 )
		{
			int mat_blocks = (num_samples_per_mat[m] + threads - 1) / threads;
			xs_lookup_kernel_optimization_4<<<mat_blocks, threads>>>(in, GSD, m, num_samples_per_mat[m], offsets[m]);
		}
	}
	gpuErrchk(cudaDeviceSynchronize());

	thrust::device_ptr<unsigned long> d_ptr(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + n_lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

